INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0489de64-moex-00191', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '北歐SAS航空前總裁JanCarlzon曾說：「去年，我們一千萬名旅客各別與5名SAS員工接觸15秒 鐘。這5千萬次的15秒關鍵時刻是決定SAS成敗的時刻。就在那一時刻，我們必須證明SAS是顧 客最好的選擇。」。下列那一項陳述最適合反映SAS總裁之觀點？', '["組織宜以顧客為焦點，第一線員工傳遞服務與顧客接觸，影響服務的成敗；管理中層與管理高層負 責支援第一線員工", "組織宜以願景為焦點，管理高層決定標的與策略，管理中層決定執行計畫，第一線員工傳遞服務予 顧客", "組織宜以股東為焦點，管理高層決定利潤目標與策略，管理中層創造收入，第一線員工負責節省成本", "組織宜以員工為焦點，管理高層協調工會領袖以決定公司策略，管理中層發展執行計畫，第一線員 工完成行動方案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00192', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '日本鐵路公司常常大量銷售定期票；如東日本鐵道公司，定期票旅客人數約占 62%，定期票旅客票 箱收入約占30%。上列事實說明：鐵路公司對下列那一市場區隔做區隔定價？', '["商務旅客", "觀光旅客", "通勤旅客", "都會區訪客"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00193', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '2003年歐洲高鐵國際列車之票價資訊如下。某中年婦女帶一位9歲小孩由布魯塞爾至巴黎之單程車 票，最便宜的支出金額是： 布魯 塞爾 巴黎', '["32", "53", "74", "90"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00194', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '某歐洲航空市場調查之結果如下圖所示，那一個市場區隔旅客之價格需求彈性（絕對值）最大？ 顧客評等', '["長假休閒旅客", "緊急商務旅客", "一般商務旅客", "周末休閒旅客"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00195', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '運輸的構成要素可分成⑴投入、⑵控制與⑶產出等 3 要素，就系統分析又分為①通路  ②場站', '["載具", "通訊  ⑤組織與⑥使用者等次系統，請選出", "～⑥次系統中為投入要素者：", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00196', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '如下圖所示，某航班由A地→B地→C地，飛機容量為100位旅客，票價按里程計費，三種機票： A→B，A→C，B→C。市場分析發現：A→B之需求量約60人，A→C之需求量約60人，B→C之需 求量約35人。建議A→B機票之最佳銷售配額為：', '["60人", "50人", "40人", "30人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00197', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '公共運輸承運人不得拒絕旅客的合理運輸要求。依鐵路法第71條，下列那一項不足以構成鐵路人員 強制旅客離開的理由？', '["拒絕鐵路站車人員查票", "列車行駛中，攀登、跳車或攀附隨行", "在車廂或站區內向旅客或公眾募捐", "於車廂隨地吐痰、檳榔汁、拋棄紙屑、污穢車廂設備之行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00198', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '有關行政機關行政協助，下列敘述何者錯誤？', '["協助之行為雖非被請求機關之權限範圍，但只要能力許可，仍應同意協助", "由被請求機關協助執行，顯較經濟者，得請求協助", "請求機關與被請求機關雖無隸屬關係，仍可請求協助", "被請求機關認為無提供行政協助之義務或有拒絕之事由時，應將其理由通知請求協助機關。請求協助機 關對此有異議時，由其共同上級機關決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00199', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '環境部委由民間機車行代為檢驗機車排氣之行政行為係屬：', '["行政命令", "行政委任", "行政委託", "行政助手"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00200', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依道路交通管理處罰條例第42條規定，汽車駕駛人不依規定使用燈光，處新臺幣1千2百元以上3千6百 元以下罰鍰，另依違反道路交通管理事件統一裁罰基準及處理細則第 2條附表（裁罰基準表）規定，民 眾於繳納期限內繳納罰鍰，違規車輛為機車或小型車者，處新臺幣1千2百元，大型車處新臺幣2千8 百元。上述處罰之裁量規定，不屬於下列何者行政法基本原則？', '["法律保留原則", "信賴保護原則", "明確原則", "公平（平等）原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
